-- ============================================================================\n-- Migration 029: Wallet Funding Denormalization for Whitelist Management\n-- ============================================================================\n-- Добавляет денормализованные колонки в таблицу wallets для прямого доступа\n-- к информации о финансировании (биржа, субаккаунт, сеть).\n-- \n-- Цель: Упростить генерацию whitelist и ускорить запросы.\n-- \n-- Добавляемые колонки:\n-- 1. funding_cex_subaccount_id → ссылка на cex_subaccounts (биржа + субаккаунт)\n-- 2. funding_network → сеть L2 для вывода с CEX\n-- 3. funding_chain_id → ссылка на funding_chains (для отладки)\n--\n-- Author: Airdrop Farming System v4.0\n-- Created: 2026-03-03\n-- ============================================================================\n\nBEGIN;\n\n-- Добавить денормализованные колонки в таблицу wallets\nALTER TABLE wallets\nADD COLUMN IF NOT EXISTS funding_cex_subaccount_id INTEGER REFERENCES cex_subaccounts(id),\nADD COLUMN IF NOT EXISTS funding_network VARCHAR(50) CHECK (funding_network IN (\n    'Base', 'Arbitrum', 'Polygon', 'BNB Chain', 'Optimism', 'Ink', 'MegaETH'\n)),\nADD COLUMN IF NOT EXISTS funding_chain_id INTEGER REFERENCES funding_chains(id);\n\n-- Индексы для быстрого поиска\nCREATE INDEX IF NOT EXISTS idx_wallets_funding_subaccount ON wallets(funding_cex_subaccount_id);\nCREATE INDEX IF NOT EXISTS idx_wallets_funding_network ON wallets(funding_network);\nCREATE INDEX IF NOT EXISTS idx_wallets_funding_chain ON wallets(funding_chain_id);\n\n-- Комментарии\nCOMMENT ON COLUMN wallets.funding_cex_subaccount_id IS \n'Денормализовано: CEX субаккаунт, который финансирует этот кошелёк (из funding_withdrawals → funding_chains)';\n\nCOMMENT ON COLUMN wallets.funding_network IS \n'Денормализовано: L2 сеть, используемая для вывода с CEX на этот кошелёк';\n\nCOMMENT ON COLUMN wallets.funding_chain_id IS \n'Денормализовано: ID funding chain (цепочки финансирования) для отладки и связей';\n\n-- Заполнить данные из существующей связи funding_withdrawals → funding_chains\nUPDATE wallets w\nSET \n    funding_cex_subaccount_id = fw.cex_subaccount_id,\n    funding_network = fw.withdrawal_network,\n    funding_chain_id = fw.funding_chain_id\nFROM funding_withdrawals fw\nWHERE w.id = fw.wallet_id\n  AND fw.direct_cex_withdrawal = TRUE;\n\n-- Проверка: подсчитать сколько кошельков обновлено\nDO $$\nDECLARE\n    updated_count INTEGER;\nBEGIN\n    SELECT COUNT(*) INTO updated_count FROM wallets WHERE funding_cex_subaccount_id IS NOT NULL;\n    RAISE NOTICE 'Обновлено % кошельков с информацией о финансировании', updated_count;\nEND $$;\n\n-- Создать VIEW для удобной генерации whitelist\nCREATE OR REPLACE VIEW v_wallets_funding_info AS\nSELECT \n    w.id as wallet_id,\n    w.address,\n    w.tier,\n    cs.exchange,\n    cs.subaccount_name,\n    w.funding_network,\n    w.funding_chain_id,\n    fc.chain_number,\n    fc.actual_wallet_count as cluster_size\nFROM wallets w\nLEFT JOIN cex_subaccounts cs ON w.funding_cex_subaccount_id = cs.id\nLEFT JOIN funding_chains fc ON w.funding_chain_id = fc.id\nORDER BY cs.exchange, cs.subaccount_name, w.funding_network, w.address;\n\nCOMMENT ON VIEW v_wallets_funding_info IS \n'Полная информация о финансировании кошельков для генерации whitelist и аудита';\n\n-- Логирование миграции\nINSERT INTO system_events (event_type, severity, message, metadata, created_at)\nVALUES (\n    'MIGRATION_COMPLETED',\n    'info',\n    'Migration 029: Wallet funding denormalization installed',\n    '{\"migration\": \"029_wallet_funding_denormalization.sql\", \"purpose\": \"whitelist generation\"}'::jsonb,\n    NOW()\n);\n\nCOMMIT;\n\n-- ============================================================================\n-- Verification Queries\n-- ============================================================================\n-- Проверить распределение по биржам:\n-- SELECT cs.exchange, COUNT(*) as wallets_count\n-- FROM wallets w\n-- JOIN cex_subaccounts cs ON w.funding_cex_subaccount_id = cs.id\n-- GROUP BY cs.exchange ORDER BY cs.exchange;\n--\n-- Проверить распределение по сетям:\n-- SELECT funding_network, COUNT(*) as wallets_count\n-- FROM wallets\n-- WHERE funding_network IS NOT NULL\n-- GROUP BY funding_network ORDER BY funding_network;\n--\n-- Проверить whitelist для конкретной биржи:\n-- SELECT cs.subaccount_name, w.funding_network, w.address\n-- FROM wallets w\n-- JOIN cex_subaccounts cs ON w.funding_cex_subaccount_id = cs.id\n-- WHERE cs.exchange = 'bybit'\n-- ORDER BY cs.subaccount_name, w.funding_network, w.address;